package com.eas.auth;
import com.eas.service.AuthService; import com.eas.util.*; import java.awt.*; import javax.swing.*;
public class RegisterFrame extends JFrame { private final JTextField user=new JTextField(),name=new JTextField(),email=new JTextField(),phone=new JTextField(),employeeNo=new JTextField(),address=new JTextField(),emergency=new JTextField(); private final JPasswordField pass=new JPasswordField();
 public RegisterFrame(){setTitle("Employee Attendance System | Register Account");setDefaultCloseOperation(EXIT_ON_CLOSE);setSize(600,570);setLocationRelativeTo(null);JPanel root=new JPanel(new BorderLayout());root.setBorder(BorderFactory.createEmptyBorder(20,45,20,45));root.add(UITheme.title("REGISTER EMPLOYEE ACCOUNT"),BorderLayout.NORTH);JPanel f=new JPanel(new GridLayout(0,2,8,9));f.setBorder(BorderFactory.createEmptyBorder(18,0,18,0));add(f,"Username *",user);add(f,"Password *",pass);add(f,"Full Name *",name);add(f,"Email *",email);add(f,"Phone",phone);add(f,"Employee Number *",employeeNo);add(f,"Address",address);add(f,"Emergency Contact",emergency);root.add(f,BorderLayout.CENTER);JPanel b=new JPanel();JButton save=UITheme.button("REGISTER");JButton back=UITheme.button("BACK TO LOGIN");b.add(save);b.add(back);root.add(b,BorderLayout.SOUTH);add(root);save.addActionListener(e->save());back.addActionListener(e->{dispose();new LoginFrame().setVisible(true);});}
 private void add(JPanel p,String l,JComponent c){p.add(new JLabel(l));p.add(c);} private void save(){try{new AuthService().registerEmployee(user.getText(),new String(pass.getPassword()),name.getText(),email.getText(),phone.getText(),employeeNo.getText(),address.getText(),emergency.getText());Dialogs.info(this,"Account registered. You can now log in.");dispose();new LoginFrame().setVisible(true);}catch(Exception ex){Dialogs.error(this,ex.getMessage());}}
}
